            os.remove(path)
        except OSError:
            pass

def {{nama_fungsi}}(path, data, encoding='utf-8'):
    """Atomic write text."""
    import os, tempfile
    dir_name = os.path.dirname(os.path.abspath(path)) or '.'
    fd, tmp_path = tempfile.mkstemp(dir=dir_name)
    try:
        with os.fdopen(fd, 'w', encoding=encoding) as f:
            f.write(data)
        os.replace(tmp_path, path)
    except Exception:
        try:
            os.remove(tmp_path)
        except OSError:
            pass
