import contextlib, os, time

@contextlib.contextmanager
def {{nama_fungsi}}(lock_path, timeout=10):
    """File lock sederhana."""
    start = time.time()
    while True:
        try:
            fd = os.open(lock_path, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
            os.close(fd)
            break
        except FileExistsError:
            if time.time() - start > timeout:
                raise TimeoutError("Could not acquire lock")
            time.sleep(0.05)
    try:
        yield
    finally:
        try:
            os.remove(lock_path)
        except OSError:
            pass

def {{nama_fungsi}}(root, interval=1.0, duration=10):
    """Yield (event, path) selama duration detik. Polling sederhana."""
    import os, time
    def snapshot():
        snap = {}
        for dirpath, _, filenames in os.walk(root):
            for name in filenames:
                p = os.path.join(dirpath, name)
                try:
                    snap[p] = os.path.getmtime(p)
                except OSError:
                    pass
        return snap
    prev = snapshot()
    end = time.time() + duration
    while time.time() < end:
        time.sleep(interval)
        cur = snapshot()
        for p in cur:
            if p not in prev:
                yield ('created', p)
            elif cur[p] != prev[p]:
                yield ('modified', p)
        for p in prev:
            if p not in cur:
                yield ('deleted', p)
        prev = cur
